# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import json
from flask import Flask, request, jsonify
from PIL import Image
from sklearn.model_selection import train_test_split
from sklearn.linear_model import LogisticRegression
from collections import Counter
import numpy as np

app = Flask(__name__)

# Data storage
data = {
    'images': {},
    'labels': {}
}

@app.route('/annotate', methods=['POST'])
def annotate():
    image_id = request.json['image_id']
    annotator_id = request.json['annotator_id']
    label = request.json['label']

    if image_id not in data['images']:
        data['images'][image_id] = []

    data['images'][image_id].append((annotator_id, label))

    return jsonify({'message': 'Label submitted successfully'}), 200

@app.route('/aggregate', methods=['POST'])
def aggregate():
    image_id = request.json['image_id']

    if image_id not in data['labels']:
        labels = [label for _, label in data['images'][image_id]]
        data['labels'][image_id] = Counter(labels).most_common(1)[0][0]

    return jsonify({'message': 'Labels aggregated successfully'}), 200

@app.route('/train', methods=['POST'])
def train():
    # Aggregate labels
    for image_id in data['images']:
        if image_id not in data['labels']:
            labels = [label for _, label in data['images'][image_id]]
            data['labels'][image_id] = Counter(labels).most_common(1)[0][0]

    # Split data into training and testing sets
    images = []
    labels = []
    for image_id, (annotators, labels_list) in data['images'].items():
        images.extend([image_id]*len(labels_list))
        labels.extend(labels_list)

    X_train, X_test, y_train, y_test = train_test_split(images, labels, test_size=0.2, random_state=42)

    # Train model
    model = LogisticRegression()
    model.fit(np.array(X_train).reshape(-1, 1), np.array(y_train))

    return jsonify({'message': 'Model trained successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)